+static int exec_command_l(int err, int *fd, const char *argv0, va_list argv) {
+    // Collect va_list into vector
+    std::vector<char *> args;
+    args.push_back(strdup(argv0));
+    for (char *arg = va_arg(argv, char*); arg; arg = va_arg(argv, char*))
