+    va_end(argv);
+    if (pid < 0)
+        return pid;
+    waitpid(pid, &status, 0);
+
+    if (WIFEXITED(status)) {
+        int returned = WEXITSTATUS(status);
+        LOGD("%s exited normally with status %d", argv0, returned);
